mapper.select:
SELECT id, register_id, session_id, doctor_id, role, content, tool_calls_json, created_at
FROM (
    SELECT *
    FROM physician_ai_chat_history
    WHERE register_id = #{registerId}
      AND session_id = #{sessionId}
    ORDER BY created_at DESC
    LIMIT #{limit}
) recent
ORDER BY created_at ASC

mapper.insert:
INSERT INTO physician_ai_chat_history (
    register_id, session_id, doctor_id, role, content, tool_calls_json, created_at
) VALUES (
    #{registerId}, #{sessionId}, #{doctorId}, #{role}, #{content}, #{toolCallsJson},
    COALESCE(#{createdAt}, NOW())
)

mapper.delete:
DELETE FROM physician_ai_chat_history
WHERE register_id = #{registerId}
  AND session_id = #{sessionId}
